const items = [];
const cutoff = Date.now() - 8 * 60 * 60 * 1000; // Letzte 8h

for (const item of $input.all()) {
  const entry = item.json;
  const pubDate = entry.pubDate || entry.isoDate;
  if (!pubDate) continue;

  const pubMs = new Date(pubDate).getTime();
  if (pubMs < cutoff) continue;

  const url = entry.link || entry.guid || '';
  const title = entry.title || '(kein Titel)';
  const feedSource = entry.feed?.title || 'Behörde';

  // Dringlichkeit erkennen
  const titleLower = title.toLowerCase();
  let priority = 'medium';
  let alertType = 'announcement';

  if (titleLower.includes('warnung') || titleLower.includes('alarm') || titleLower.includes('notfall')) {
    priority = 'urgent';
    alertType = 'warning';
  } else if (titleLower.includes('massnahme') || titleLower.includes('verordnung') || titleLower.includes('gesetz')) {
    priority = 'high';
    alertType = 'regulation';
  }

  items.push({
    json: {
      source: 'government',
      source_id: url || `gov-${pubMs}`,
      summary: `[${feedSource}] ${title}`,
      priority: priority,
      customer_id: $env.CUSTOMER_ID || null,
      buddy_id: $env.BUDDY_ID || null,
      timestamp: pubDate,
      details: {
        agency: feedSource,
        alert_type: alertType,
        title: title,
        official_url: url,
        published_at: pubDate,
        region: $env.CUSTOMER_REGION || 'Schweiz'
      }
    }
  });
}

return items.slice(0, 10);
